/**
 * Company logo SVG data for experience cards and trusted-by section.
 * Each entry maps a company name to its logo definition.
 * Uses inline SVG paths to avoid external image dependencies.
 *
 * Logos include light/dark color variants so they remain legible
 * against both theme backgrounds.
 */

export interface CompanyLogo {
  /** SVG viewBox */
  viewBox: string;
  /** SVG path data */
  paths: ReadonlyArray<{ d: string; fill?: string }>;
  /** Brand color used for the initial-circle fallback */
  color: string;
  /** Fill colour override for light mode (applied to all paths without an explicit fill) */
  lightFill?: string;
  /** Fill colour override for dark mode */
  darkFill?: string;
}

