/* ------------------------------------------------------------------ */
/*  Registry                                                          */
/* ------------------------------------------------------------------ */

/**
 * Map of company / institution names (lowercase) to their logo definitions.
 * Logos are designed for small display (24-32px) with dark/light variants.
 */
export const COMPANY_LOGOS: Record<string, CompanyLogo> = {
  areeba: AREEBA,
  "cme offshore": CME_OFFSHORE,
  tecfrac: TECFRAC,
  deloitte: DELOITTE,
  revinate: REVINATE,
  klareo: KLAREO,
  "dga saudi arabia": DGA_SAUDI,
  "arizona state university": ASU,
  "american university of beirut": AUB,
};

/**
 * Look up a company logo by name (case-insensitive).
 */
export function getCompanyLogo(company: string): CompanyLogo | undefined {
  return COMPANY_LOGOS[company.toLowerCase()];
}
